import type {ArticleSection} from '../types/philosophy';

const section=(id:string,title:string,paragraphs:string[],relatedBranchIds?:string[],relatedPhilosopherIds?:string[],relatedWorkTitles?:string[]):ArticleSection=>({id,title,paragraphs,relatedBranchIds,relatedPhilosopherIds,relatedWorkTitles});

export const postKantianNineteenthPhilosopherArticles:Record<string,ArticleSection[]>={
  hegel:[
    section('overview','Reason as historical development',[
      "Hegel is the central post-Kantian philosopher of development, conflict, and reconciliation. He argues that reason is not a private faculty sealed inside an individual mind and not a fixed set of abstract rules hovering above history. Reason becomes actual through forms of life: language, law, family, work, religion, art, politics, and philosophy. Human beings learn what freedom means only by passing through institutions and conflicts that expose one-sided ideas of freedom.",
      "This makes Hegel difficult and important. He is not merely saying that history improves automatically or that every event is rational. He is asking how concepts become concrete. A person may say that freedom means doing whatever one wants, but social life shows that desire depends on recognition, law, education, and shared norms. Hegel follows the movement from simple claims to richer ones, showing how an idea can fail by being too abstract and then return in a fuller form.",
      "The basic beginner mistake is to look for Hegel's final slogan before seeing the problem he is trying to solve. He wants to explain how finite viewpoints can be partial without being meaningless, and how conflict can reveal the hidden dependence of each side on the other. His system is therefore not a shortcut around history. It is an attempt to think historically without surrendering intelligibility."
    ],['german-idealism','continental-philosophy','metaphysics'],['kant','hegel'],['Phenomenology of Spirit']),
    section('setting','After Kant, revolution, and modern fragmentation',[
      "Hegel wrote after Kant had transformed philosophy by asking how experience and moral obligation are possible for finite knowers. Kant left powerful divisions: appearance and thing in itself, nature and freedom, knowledge and faith, duty and inclination. German Idealists tried to overcome these separations without returning to pre-critical metaphysics. Hegel accepted Kant's depth but thought critical philosophy remained too dualistic unless reason could understand its own historical and social actuality.",
      "The political setting mattered just as much. Hegel lived through the French Revolution, the Napoleonic wars, the reorganization of German territories, and the rise of modern bureaucratic states. Revolution showed the power of universal freedom; terror and instability showed the danger of abstract freedom detached from institutions. Hegel's political philosophy grows from this double lesson. Modernity must honor individual freedom, but freedom needs durable ethical life rather than heroic declarations alone."
    ],['german-idealism','political-philosophy'],['kant','hegel'],[]),
    section('life-works','Life, teaching, and the shape of the corpus',[
      "Hegel was born in Stuttgart in 1770, studied theology and philosophy at Tubingen, worked as a tutor and editor, taught at Jena, Nuremberg, Heidelberg, and finally Berlin, where he became a major public philosopher. His career was not a straight ascent. The Phenomenology of Spirit appeared in 1807 amid political crisis, and later works were written for lecture halls and students as well as for specialist readers.",
      "The major works form a demanding architecture. The Phenomenology follows consciousness through experiences that undo its own certainties. The Science of Logic examines the movement of pure categories. The Encyclopedia compresses logic, nature, and spirit into a system. The Philosophy of Right analyzes modern ethical and political life. Lectures on history, art, religion, and philosophy were edited from student notes after his death, so they must be read with care about textual status."
    ],['german-idealism','continental-philosophy'],['hegel'],['Phenomenology of Spirit','Science of Logic','Philosophy of Right']),
    section('dialectic','Dialectic without the cartoon formula',[
      "Hegel is often reduced to thesis, antithesis, synthesis, but that formula is not a reliable guide to his method. Dialectic is better understood as the self-examination of a position whose own commitments generate pressure. A view presents itself as complete, but when it is followed carefully it reveals dependence on what it first excluded. The result is not a compromise in the middle. It is a new shape that preserves what was true in the earlier view while correcting its one-sidedness.",
      "A beginner can see the pattern in ordinary examples. Pure independence sounds free, but a person who refuses every relation lacks recognition, language, and practical identity. Pure conformity supplies belonging, but erases agency. A richer account of freedom must include both selfhood and relation. Hegel's dialectic is an attempt to think such developments from within, not by externally adding qualifications whenever a theory looks too simple."
    ],['german-idealism','metaphysics'],['hegel'],['Phenomenology of Spirit','Science of Logic']),
    section('phenomenology','The Phenomenology as an education of consciousness',[
      "The Phenomenology of Spirit begins with apparently immediate certainty and shows why immediacy cannot support knowledge by itself. Sense-certainty thinks it possesses the singular this, but its language uses universals such as here and now. Perception tries to stabilize things and properties, but encounters contradiction. Understanding looks for forces and laws behind appearances. Each stage is not simply refuted from outside; it discovers that its own standard of truth requires a more complex account.",
      "The book then moves through self-consciousness, reason, ethical life, culture, morality, religion, and absolute knowing. It is an education in losing false certainties. Absolute knowing does not mean that a human mind knows every fact. It means that spirit has learned that truth is not a dead object opposite the knower. Truth is a process in which knowing and its object have histories, and philosophy grasps that history as intelligible."
    ],['german-idealism','epistemology','metaphysics'],['kant','hegel'],['Phenomenology of Spirit']),
    section('recognition','Self-consciousness and recognition',[
      "One of Hegel's most influential arguments concerns recognition. Self-consciousness does not become fully itself by staring inward. It needs another self-conscious being who can recognize it as free, responsible, and answerable. The famous master and bondsman passage explores a failed form of recognition. The master receives acknowledgment from someone treated as dependent, but that acknowledgment is unstable because it comes from a person denied equal standing.",
      "The bondsman, through fear, discipline, and labor, discovers a relation to the world that the master lacks. This is not a simple political allegory and should not be treated as a direct prophecy of class struggle. It is a philosophical analysis of dependency, work, and the need for reciprocal recognition. Later thinkers in existentialism, Marxism, feminism, critical theory, and social philosophy repeatedly return to this passage because it shows that freedom is relational."
    ],['continental-philosophy','political-philosophy'],['hegel','marx'],['Phenomenology of Spirit']),
    section('logic-metaphysics','Logic, being, essence, and concept',[
      "Hegel's Logic is not formal logic in the modern symbolic sense, although it is rigorous and argumentative. It asks how the most basic categories of thought and being develop. The opening with pure being, nothing, and becoming is famously difficult because Hegel is not describing three objects. He is testing whether the thinnest possible category, pure being without determination, can be thought as meaningful. Its emptiness collapses into nothing, and their instability becomes becoming.",
      "The larger movement through being, essence, and concept shows Hegel's rejection of inert metaphysical furniture. Categories are not labels pasted onto reality after the fact. They articulate intelligibility itself. Essence involves mediation, appearance, ground, and relation; concept involves self-determining universality, particularity, and individuality. Critics ask whether this grants thought too much power over reality. Defenders answer that Hegel is not making reality mental in a simple sense, but showing that any intelligible reality is structured through determinate relations."
    ],['metaphysics','german-idealism'],['hegel','kant'],['Science of Logic']),
    section('ethical-life','Ethical life, civil society, and the state',[
      "In the Philosophy of Right, Hegel distinguishes abstract right, morality, and ethical life. Abstract right concerns persons as bearers of property and legal standing. Morality concerns intention, responsibility, and conscience. Ethical life, or Sittlichkeit, names the institutions in which freedom becomes shared practice: family, civil society, and the state. Hegel thinks modern freedom cannot live only in private conscience or market exchange. It requires institutions that educate desire and give rights practical form.",
      "Civil society is especially modern. It includes work, needs, markets, corporations, poverty, administration, and mutual dependence among strangers. Hegel does not romanticize it as harmonious. It produces wealth, specialization, and freedom, but also instability and exclusion. The state is supposed to integrate these tensions through law and public institutions. This is one reason his politics remains contested. Some readers see a defense of rational constitutional life; others see excessive trust in the modern state."
    ],['political-philosophy','german-idealism'],['hegel','marx'],['Philosophy of Right']),
    section('history-freedom','History as the development of freedom',[
      "Hegel's philosophy of history argues that world history can be understood as progress in the consciousness of freedom. This does not mean steady moral improvement or that every suffering person is compensated by a larger plan. Hegel is trying to identify a pattern in which forms of political and ethical life make freedom more explicit. Ancient communities may embody shared ethical substance, but often at the cost of individual subjectivity. Modernity makes individual freedom central, but must learn how to institutionalize it.",
      "The danger is obvious: such a view can become triumphalist, Eurocentric, or too forgiving of violence. Hegel's own historical lectures contain exclusions and hierarchies that modern readers should not excuse. The strongest use of his approach keeps the critical question alive: what form of life allows people to recognize themselves and one another as free? The weakest use turns history into a victory story told by those already in power."
    ],['german-idealism','political-philosophy'],['hegel','marx'],['Lectures on the Philosophy of History']),
    section('art-religion','Art, religion, and philosophy as forms of spirit',[
      "Hegel treats art, religion, and philosophy as ways spirit understands itself. Art gives truth sensible shape; religion represents truth through images, narratives, and communal worship; philosophy grasps truth conceptually. This ordering has often been misunderstood as simple contempt for art or religion. Hegel is not saying that art becomes worthless. He thinks art may no longer carry the highest self-understanding of modern culture in the way it once did for Greek ethical life.",
      "His philosophy of religion is likewise complex. Hegel reads Christianity as a profound representation of reconciliation, alienation, incarnation, death, and community, but he translates religious content into speculative concepts. Critics see reduction of faith to philosophy. Supporters see an attempt to understand religious life without dismissing it as irrational. The tension matters for later theology, secularization debates, and continental philosophy, where Hegel becomes both resource and opponent."
    ],['philosophy-of-religion','aesthetics','continental-philosophy'],['hegel','kierkegaard'],['Lectures on the Philosophy of Religion','Lectures on Aesthetics']),
    section('legacy','Marx, existentialism, critical theory, and analytic suspicion',[
      "Hegel's influence is enormous because later thinkers inherit both his problems and his vocabulary. Marx transforms Hegelian dialectic by grounding social conflict in material production, labor, and class relations. Kierkegaard attacks the system from the standpoint of existing individual commitment. Nietzsche, phenomenology, hermeneutics, existentialism, pragmatism, and critical theory all respond in different ways to the idea that reason, history, and social recognition are intertwined.",
      "Hegel also provoked deep suspicion. Some analytic philosophers treated him as obscure metaphysics; liberal critics feared authoritarian politics; religious critics saw rationalization of faith; historical critics challenged his exclusions. Recent readings often recover him as a theorist of normativity, recognition, social freedom, and modern institutions. The disagreement is healthy. Hegel is at his worst when treated as an oracle, and at his best when his claim that freedom must become concrete is tested against actual social life."
    ],['continental-philosophy','political-philosophy','german-idealism'],['hegel','marx','kierkegaard','nietzsche'],['Phenomenology of Spirit','Philosophy of Right']),
    section('reading-strategy','How to read Hegel without giving up',[
      "A sensible route begins with the problem rather than the system. Read a short introduction to Kant's critical philosophy, then selected prefaces and introductions by Hegel. The Introduction to the Phenomenology is hard but valuable because it explains why consciousness must test its own standards. The lordship and bondage, unhappy consciousness, and ethical life sections can then be read slowly with guidance. Do not expect every sentence to yield immediately.",
      "After that, read parts of the Philosophy of Right on abstract right, morality, family, civil society, and the state. The Science of Logic is best approached later, with commentary, because its difficulty is conceptual rather than merely verbal. Keep a notebook of oppositions Hegel is trying to overcome: individual and society, freedom and law, thought and world, religion and philosophy. Hegel becomes clearer when read as a philosopher of mediation, not as a collector of slogans about dialectic."
    ],['german-idealism','continental-philosophy'],['kant','hegel','marx'],['Phenomenology of Spirit','Science of Logic','Philosophy of Right'])
  ],
  schopenhauer:[
    section('overview','A dark metaphysics of will and suffering',[
      "Schopenhauer is one of the great philosophical pessimists, but his pessimism is not just a gloomy mood. He argues that beneath the ordered world of objects lies will: restless striving without final satisfaction. Human beings experience this will most directly in their own embodied desire, need, frustration, boredom, and conflict. Reason helps us navigate the world, but it does not rule the deepest structure of existence.",
      "His philosophy combines Kantian idealism, Platonic aesthetics, Buddhist and Hindu materials as he understood them, and a severe moral psychology. The result is a system that treats ordinary optimism as evasion. Life is not made meaningful by progress, social success, or clever calculation. Yet Schopenhauer does not stop at despair. He searches for partial release in art, compassion, and the quieting of willing. The question is whether such release can be philosophically defended."
    ],['metaphysics','ethics','continental-philosophy'],['kant','schopenhauer','nietzsche'],['The World as Will and Representation']),
    section('life-context','A solitary critic of academic optimism',[
      "Arthur Schopenhauer was born in 1788 into a wealthy Danzig merchant family, lived amid European upheavals, and developed a self-conscious distance from academic philosophy. He studied Kant and Plato intensely, wrote his dissertation on the principle of sufficient reason, and published The World as Will and Representation in 1818. The book initially received little attention. Schopenhauer later became famous only after decades of disappointment, polemic, and revisions.",
      "His hostility toward Hegel and university philosophy was fierce and often ungenerous. He saw post-Kantian idealism as inflated abstraction and accused Hegelian philosophy of obscuring rather than clarifying experience. The personal bitterness should not be confused with the philosophical disagreement, but it shaped his style. Schopenhauer writes with unusual directness, literary force, and contempt for fashionable optimism. Readers should separate the power of his diagnosis from his vanity, prejudice, and frequent unfairness toward rivals."
    ],['metaphysics','german-idealism'],['kant','hegel','schopenhauer'],['The World as Will and Representation']),
    section('kantian-inheritance','Kant transformed into metaphysical pessimism',[
      "Schopenhauer begins from Kant's distinction between appearances and the thing in itself. The world as representation is the world as it appears under the forms of space, time, and causality to a subject. Objects are not simply there without relation to knowing; they are objects within experience. Schopenhauer accepts much of this framework, but he thinks Kant left the thing in itself too unknowable and treated moral reason with too much dignity.",
      "His bold move is to identify the thing in itself, at least as accessible through our inner experience, with will. We do not know ourselves only as objects in space. We also know bodily action from within as striving. The body is both representation and will. Schopenhauer then extends this clue to nature as a whole. Gravity, growth, animal impulse, and human desire are different objectifications of a blind striving that has no final rational purpose."
    ],['metaphysics','german-idealism'],['kant','schopenhauer'],['The World as Will and Representation']),
    section('representation','The world as representation',[
      "The phrase world as representation does not mean that the world is imaginary. It means that whatever appears as an object appears in relation to a subject and through forms of cognition. Space, time, causality, and individuation structure the world of ordinary experience. Scientific explanation operates within this domain, connecting events according to the principle of sufficient reason. It is powerful, but it explains relations among appearances rather than the ultimate inner character of reality.",
      "This gives Schopenhauer a double attitude toward science and common sense. He respects empirical inquiry within its limits, but denies that it can answer the deepest metaphysical question. Physics may describe forces; biology may describe reproduction and adaptation; psychology may describe motives. Yet the inner meaning of all these processes, he argues, is striving. The world appears as orderly representation, but its core is not a rational plan. It is will seeking expression."
    ],['epistemology','metaphysics'],['kant','schopenhauer'],['On the Fourfold Root of the Principle of Sufficient Reason','The World as Will and Representation']),
    section('will-body','The body as the key to will',[
      "Schopenhauer's most famous argument turns on the body. If I knew my body only as an object among objects, I would never escape the standpoint of representation. But I also experience my body as willing: reaching, hungering, fearing, desiring, resisting pain. Action is not first observed as an external event and then guessed to have an inner cause. It is lived from within. This inner access gives Schopenhauer his model for the thing in itself.",
      "The move is controversial. Does inner bodily experience really justify a metaphysics of all nature? Schopenhauer thinks it does because the same pattern of striving appears everywhere at different grades of objectification. Critics reply that this projects human desire onto the world. Still, the argument has lasting force because it refuses to treat consciousness as a detached spectator. We are embodied need before we are neutral observers, and philosophy must account for that fact."
    ],['metaphysics','philosophy-of-mind'],['schopenhauer','kant'],['The World as Will and Representation']),
    section('suffering','Desire, boredom, and the structure of suffering',[
      "Schopenhauer's pessimism rests on a simple but severe pattern. Desire is lack, so willing begins in dissatisfaction. If desire is frustrated, we suffer. If desire is satisfied, the satisfaction is temporary and gives way to new desire or boredom. Happiness is therefore mostly negative: relief from pain rather than stable possession of a positive good. The will does not reach final completion because it has no final rational end.",
      "This diagnosis attacks philosophies of progress and common promises of fulfillment. Wealth, romance, honor, political achievement, and knowledge may change the contents of striving, but not its structure. Schopenhauer can be unfair to ordinary joys, friendships, and forms of meaning that are not reducible to appetite. Yet he remains philosophically powerful because he asks whether many human projects secretly depend on postponing satisfaction forever. His pessimism is an analysis of recurrence, not simply sadness."
    ],['ethics','metaphysics'],['schopenhauer'],['The World as Will and Representation']),
    section('aesthetics','Art as temporary release',[
      "Art offers one of Schopenhauer's main forms of relief. In aesthetic contemplation, the subject becomes absorbed in the object without practical desire. Instead of asking how something serves my needs, I attend to its form, rhythm, or idea. This suspends the ordinary pressure of will. Painting, poetry, tragedy, architecture, and especially music can free us temporarily from anxious individuality and reveal patterns of existence without demanding possession.",
      "Music receives the highest place because Schopenhauer thinks it does not merely copy appearances. It expresses the movement of will more directly than the visual arts. This claim deeply influenced later artists and composers, even where they rejected his system. The release remains temporary. After aesthetic experience, willing returns. Still, art matters because it shows that consciousness can loosen its bondage to desire and encounter the world without immediate self-interest."
    ],['aesthetics','metaphysics'],['schopenhauer','nietzsche'],['The World as Will and Representation']),
    section('compassion','Compassion and the basis of ethics',[
      "Schopenhauer rejects Kant's attempt to ground morality in rational law alone. For him, genuine moral action arises when the boundary between self and other becomes less absolute and another being's suffering is felt as directly significant. Compassion interrupts egoism. It does not calculate advantage or obey an abstract formula. It recognizes that the same will lives and suffers in all beings, even though representation divides us into individuals.",
      "This ethics leads Schopenhauer to unusual concern for animals compared with many earlier European philosophers. If suffering is morally central, then the capacity to suffer matters more than rational status alone. Yet the basis remains debated. Does compassion depend on a metaphysical identity of will, or can it stand as a psychological and ethical fact? Schopenhauer's answer joins both. He wants compassion to reveal a metaphysical truth about individuation as appearance."
    ],['ethics','metaphysics'],['kant','schopenhauer'],['On the Basis of Morality']),
    section('asceticism','Denial of the will and salvation without triumph',[
      "The deepest release for Schopenhauer is not better satisfaction of desire but denial of the will. Ascetic practice, saintliness, chastity, voluntary poverty, and resignation are signs that the will has turned against its own endless striving. This is not suicide in his view, because suicide remains a desperate act of will against painful conditions. Denial of the will is a more radical quieting of attachment to individual existence.",
      "This doctrine is difficult for modern readers. It can sound life-denying, psychologically unhealthy, or hostile to ordinary love and creativity. Schopenhauer would answer that ordinary affirmation mostly repeats suffering. The issue is not easy. His account gives philosophical dignity to renunciation and compassion, but it also risks undervaluing active forms of solidarity, reform, and joy. Nietzsche later attacks this ascetic ideal as a symptom of resentment against life, even while learning from Schopenhauer's honesty about suffering."
    ],['ethics','metaphysics'],['schopenhauer','nietzsche'],['The World as Will and Representation']),
    section('religion-east-west','Religion, Indian texts, and cautious comparison',[
      "Schopenhauer admired the Upanishads and Buddhist ideas as available to him through nineteenth-century European translations and scholarship. He believed they confirmed insights about appearance, desire, suffering, and release. His engagement helped many European readers take Indian philosophy seriously, but it also passed through limited sources, orientalist assumptions, and selective interpretation. He was not a reliable guide to the full diversity of Hindu or Buddhist traditions.",
      "His relation to Christianity is similarly selective. He praises ascetic and compassionate strands while criticizing optimism, providential history, and institutional dogma. He often treats religions as symbolic expressions of metaphysical insight for people who do not grasp philosophy conceptually. This can be illuminating and reductive at the same time. Responsible reading avoids both dismissing his cross-cultural interest and treating his interpretations as neutral descriptions of Asian or Christian thought."
    ],['philosophy-of-religion','metaphysics'],['schopenhauer'],['The World as Will and Representation']),
    section('influence','From Nietzsche to modern suspicion',[
      "Schopenhauer shaped nineteenth and twentieth-century thought far beyond academic metaphysics. Nietzsche began as a passionate admirer before turning against the denial of the will. Wagner, Tolstoy, Freud, Thomas Mann, and many other writers and artists found in Schopenhauer a language for desire, suffering, illusion, and art. His emphasis on unconscious striving helped prepare later suspicion toward rational self-transparency, even though Freud's theories are not simply Schopenhauer in medical form.",
      "He also influenced debates in ethics, aesthetics, animal suffering, and pessimism. Contemporary readers sometimes return to him through questions about antinatalism, environmental exhaustion, consumer desire, and the gap between satisfaction and well-being. His legacy is strongest when pessimism is treated as a challenge rather than a pose. If he is wrong, philosophy still owes an answer to his central question: why should striving be trusted as a path to happiness?"
    ],['continental-philosophy','ethics','aesthetics'],['schopenhauer','nietzsche'],['The World as Will and Representation']),
    section('misreadings-reading','Misunderstandings and how to read Schopenhauer',[
      "Common misunderstandings flatten Schopenhauer into mere depression, misanthropy, or artistic melancholy. His philosophy is darker and more systematic than that. It includes a theory of cognition, a metaphysics of embodiment, an aesthetics of contemplation, and an ethics of compassion. Another mistake is to treat will as ordinary conscious choice. Will is deeper than deliberate decision; conscious motives are surface expressions of a striving that precedes reflective control.",
      "A good reading strategy begins with the dissertation only if one wants the technical background. Most readers should start with the first volume of The World as Will and Representation, moving slowly through representation, will, art, and ethics. The essays On the Basis of Morality and On the Suffering of the World can clarify central themes. Keep Kant nearby, but do not reduce Schopenhauer to a footnote to Kant. His originality lies in turning transcendental idealism toward embodiment, suffering, and release.",
      "Read him with two kinds of resistance. First, resist the temptation to dismiss him because the conclusions are bleak or the tone is abrasive. Second, resist the temptation to admire the bleakness as if severity itself proved truth. The strongest question to carry through the work is whether his account of desire explains too much, or whether ordinary optimism explains too little.",
      "It is also useful to separate diagnosis from prescription. Schopenhauer may be persuasive when describing the recurring dissatisfaction built into desire, yet less persuasive when recommending resignation as the highest response. Readers can grant the force of his account of suffering while asking whether compassion, art, friendship, reform, or shared work might answer suffering without denying the will altogether."
    ],['metaphysics','ethics','continental-philosophy'],['kant','schopenhauer','nietzsche'],['The World as Will and Representation','On the Basis of Morality'])
  ],
  kierkegaard:[
    section('overview','Becoming a self before God',[
      "Kierkegaard is a philosopher of inwardness, anxiety, choice, faith, and the difficulty of becoming a self. He does not begin from the question of how to build a complete system of reality. He asks how an existing person lives, chooses, avoids decision, loves, despairs, and stands before God. Truth matters, but the truth that changes a life cannot be possessed like a detached theorem.",
      "This makes Kierkegaard a major precursor of existentialism, though he was a Christian thinker rather than a secular existentialist. He writes against complacent Christendom, against speculative systems that absorb existence into concepts, and against easy cultural religion. The individual is not an isolated consumer of private feelings. The individual is the person who must answer for a life that no crowd, institution, or theory can live on their behalf."
    ],['existentialism','philosophy-of-religion','ethics'],['kierkegaard','hegel'],['Fear and Trembling','The Sickness Unto Death']),
    section('copenhagen','Copenhagen, Christendom, and social pressure',[
      "Soren Kierkegaard lived most of his life in Copenhagen, a small but intellectually active city where church, university, press, theater, and social reputation overlapped. He inherited wealth, studied theology, broke an engagement with Regine Olsen, and became a public author whose life and writings were watched closely. His attack on established Christendom near the end of his life was not an abstract complaint. It was directed at a society where being Christian could become a cultural label rather than a demanding form of existence.",
      "The local setting helps explain his obsession with the crowd, publicity, and leveling. Kierkegaard feared that modern public opinion could dissolve responsibility by making everyone a spectator. A person may repeat moral or religious language because it is socially expected while never choosing it inwardly. His criticism of the crowd does not mean hatred of other people. It is a warning that collective approval can become a way to avoid the burden of deciding."
    ],['existentialism','philosophy-of-religion'],['kierkegaard'],[]),
    section('pseudonyms','Pseudonyms and indirect communication',[
      "Kierkegaard wrote many works under pseudonyms: Johannes de Silentio, Victor Eremita, Johannes Climacus, Anti-Climacus, and others. These names are not disguises for a single doctrine. They are literary voices that stage possibilities of existence. One pseudonym may speak from aesthetic detachment, another from ethical seriousness, another from religious passion, another from a position that Kierkegaard himself does not simply endorse. The reader must learn to ask who is speaking and what form of life that voice represents.",
      "This is part of what Kierkegaard calls indirect communication. If the problem is that readers possess Christian or ethical concepts without living them, then a direct lecture may only add more information. A literary construction can unsettle the reader, expose evasions, and make a choice visible. The goal is not confusion for its own sake. It is communication suited to existing persons, for whom the deepest task is appropriation rather than passive agreement."
    ],['existentialism','philosophy-of-language'],['kierkegaard'],['Either/Or','Concluding Unscientific Postscript']),
    section('subjectivity','Subjective truth and passionate appropriation',[
      "Kierkegaard's claim that truth is subjectivity is often misunderstood as relativism. He is not saying that facts do not matter or that any belief becomes true if felt intensely. He distinguishes objective questions, where detached inquiry is appropriate, from existential truths, where the issue is how a person relates to what is known. To know that one is mortal, guilty, loved, obligated, or called by God is not like knowing the date of an event.",
      "Subjective truth means that the knower is implicated. A person can explain Christianity, ethics, or love with scholarly accuracy while remaining untouched by it. Conversely, passionate commitment without concern for truth can become fanaticism. Kierkegaard's point is the relation: the existing individual must appropriate a truth inwardly and live from it. This makes philosophy answerable to self-deception, delay, and the gap between what one says and what one is becoming."
    ],['existentialism','epistemology','philosophy-of-religion'],['kierkegaard'],['Concluding Unscientific Postscript']),
    section('stages','Aesthetic, ethical, and religious forms of life',[
      "Kierkegaard often presents life through aesthetic, ethical, and religious stages or spheres. The aesthetic life seeks possibility, pleasure, interesting experience, and escape from boredom. It may be crude sensuality or refined irony, but it avoids binding commitment. The ethical life accepts responsibility, continuity, promise, duty, and the formation of character. It understands the self through choices that can be justified within shared moral life.",
      "The religious sphere does not simply discard the ethical, but it reveals a relation to God that cannot be reduced to social respectability. These stages are not a neat ladder every person climbs once. They are existential possibilities that can coexist, return, or be mimicked. An aesthetic person can use ethical language; an ethical person can hide from religious inwardness; a religious person can be tempted by admiration. Kierkegaard maps ways of existing, not personality types for easy classification."
    ],['existentialism','ethics','philosophy-of-religion'],['kierkegaard'],['Either/Or',"Stages on Life's Way"]),
    section('anxiety-despair','Anxiety, despair, and the self',[
      "The Concept of Anxiety treats anxiety as the dizziness of freedom. Anxiety differs from ordinary fear because fear has a definite object, while anxiety arises before possibility. A person can choose, and this openness is both gift and burden. Kierkegaard connects anxiety to sin, innocence, and the emergence of selfhood. The point is not to provide clinical psychology, although later psychology learned from him. It is to show that freedom is experienced before it is theorized.",
      "The Sickness Unto Death defines the self as a relation that relates itself to itself and is grounded in God. Despair occurs when the self misrelates: not wanting to be oneself, wanting to be oneself without dependence, or living unaware that one is a self before God. This analysis is spiritually severe because despair can hide under success, busyness, social approval, or cultivated identity. Kierkegaard treats despair as a condition of selfhood gone wrong, not merely a feeling of sadness."
    ],['existentialism','philosophy-of-religion','philosophy-of-mind'],['kierkegaard'],['The Concept of Anxiety','The Sickness Unto Death']),
    section('faith-abraham','Fear and Trembling and the scandal of faith',[
      "Fear and Trembling centers on Abraham and Isaac, asking what faith means if Abraham's willingness to sacrifice Isaac cannot be justified by ordinary ethical universality. Johannes de Silentio describes Abraham as a knight of faith, but also insists that he cannot understand him. The book is not a simple endorsement of private violence. It is an attempt to show the terror of a relation to God that exceeds ethical explanation.",
      "The phrase teleological suspension of the ethical has caused lasting debate. Kierkegaard is not giving everyone permission to break moral law in the name of inner certainty. He is dramatizing the paradox that biblical faith seems to place the single individual in an absolute relation to God. Many readers reject the view as dangerous; others see it as exposing the difference between admiration for faith and the actual cost of faith. The book's power lies in refusing to make faith comfortable."
    ],['philosophy-of-religion','ethics','existentialism'],['kierkegaard'],['Fear and Trembling']),
    section('love-and-neighbor','Love, neighbor, and hidden inwardness',[
      "Works of Love corrects the idea that Kierkegaard is only a thinker of solitary inwardness. Christian love, for him, is commanded love of the neighbor. The neighbor is not merely the friend, beloved, or admired person. The neighbor is the other person as equal before God. This makes love less dependent on preference and more demanding than romantic or social attachment. It also guards against making inwardness a private aesthetic achievement.",
      "The command to love does not erase affection, but it tests it. Preferential loves can become possessive or self-flattering unless transformed by neighbor-love. Kierkegaard's ethics is therefore not simple individualism. The individual before God is returned to others under a different description. This is one of the best ways to resist a common misunderstanding: inwardness is not withdrawal from responsibility. It is the depth from which responsibility becomes genuinely chosen."
    ],['ethics','philosophy-of-religion'],['kierkegaard'],['Works of Love']),
    section('against-system','Hegel, system, and existing thought',[
      "Kierkegaard's relation to Hegel is complex. He opposed the Hegelian tendency, as he understood it, to absorb individual existence into historical and conceptual mediation. A system may explain world history, religion, ethics, and logic, but no system can exist for me. The existing individual must choose, suffer, repent, believe, and die. Kierkegaard thought speculative philosophy risked confusing conceptual comprehension with existential transformation.",
      "This criticism can be unfair to Hegel, whose account of spirit also includes conflict, recognition, and ethical life. Still, Kierkegaard identifies a real danger in grand theory: the person who explains everything may avoid becoming anyone. His polemic is strongest when aimed at the reader's temptation to substitute intellectual mastery for inward responsibility. He does not abolish thought. He asks thought to remember that it belongs to an existing thinker."
    ],['existentialism','german-idealism','philosophy-of-religion'],['hegel','kierkegaard'],['Concluding Unscientific Postscript']),
    section('authorship','The authorship as a strategy of awakening',[
      "Kierkegaard described his authorship as a religious project, though it includes aesthetic literature, philosophical satire, psychological analysis, sermons, polemics, and devotional writings. The early pseudonymous works often draw readers into attractive forms of life before exposing their limits. The signed discourses speak more directly in a Christian voice. The later attack on Christendom turns from indirect seduction toward open confrontation with established religious complacency.",
      "The unity of the authorship remains disputed. Some readers emphasize its Christian aim from beginning to end. Others stress literary multiplicity, irony, and resistance to final interpretation. Both capture something important. Kierkegaard built a body of writing that refuses to let the reader remain a spectator. Even the question of how the works fit together becomes part of the task: do I want a map of the authorship, or do I want to evade what the map asks of me?"
    ],['existentialism','philosophy-of-religion'],['kierkegaard'],['Either/Or','Concluding Unscientific Postscript','Works of Love']),
    section('legacy','Existentialism, theology, psychology, and modern selfhood',[
      "Kierkegaard influenced existentialism, Protestant theology, phenomenology, psychology, literary modernism, and critiques of mass society. Heidegger drew on anxiety and existence while transforming them outside Kierkegaard's explicitly Christian frame. Sartre and Camus inherit problems of choice, responsibility, and meaning while rejecting Kierkegaard's faith. Twentieth-century theologians used him to challenge cultural Christianity and recover the offense of revelation.",
      "His modern relevance is not only religious. He helps diagnose distraction, performative identity, public opinion, and the fear of commitment. But secular appropriation should not erase the theological core of his project. Kierkegaard is not merely a lifestyle writer about authenticity. He is asking whether the self can be healed without acknowledging its dependence on God. Even readers who reject that answer can learn from the seriousness of the question."
    ],['existentialism','philosophy-of-religion','continental-philosophy'],['kierkegaard','nietzsche','hegel'],['The Sickness Unto Death','The Concept of Anxiety']),
    section('misreadings-reading','Misunderstandings and how to read Kierkegaard',[
      "Common misunderstandings treat Kierkegaard as an irrationalist, a pure individualist, or a writer who celebrates arbitrary choice. He is better read as a critic of detached reason when it evades existence, not of careful thinking as such. Choice matters because it forms the self, but choice is not valuable merely because it is choice. Faith is passionate, but not a generic leap into whatever one prefers.",
      "A good route begins with selections from Either/Or to feel the aesthetic and ethical contrast, then Fear and Trembling for the difficulty of faith, The Concept of Anxiety for freedom, Works of Love for neighbor ethics, and The Sickness Unto Death for the self. Read pseudonyms as voices, not as automatic mouthpieces. Keep the question personal but not merely subjective: what would it mean for a truth to require me, rather than simply inform me?",
      "It also helps to read Kierkegaard slowly enough to notice his humor. The elaborate titles, invented editors, seducers, judges, and anti-systematic performances are not decorations around a doctrine. They are part of the diagnosis. He is watching how people hide from themselves through cleverness, respectability, despair, romance, scholarship, and even religious language. The reader is meant to feel implicated.",
      "For that reason, Kierkegaard is best read with pauses rather than as a list of positions. Ask what temptation each text exposes. Is the temptation aesthetic escape, ethical pride, religious imitation, public approval, or philosophical mastery? The works become clearer when they are treated as mirrors for evasions, not only as arguments about concepts."
    ],['existentialism','philosophy-of-religion','ethics'],['kierkegaard'],['Either/Or','Fear and Trembling','The Concept of Anxiety','Works of Love','The Sickness Unto Death'])
  ],
  marx:[
    section('overview','Philosophy turned toward material social life',[
      "Marx changes philosophy by insisting that ideas, laws, politics, morality, and religion must be understood in relation to material social life. Human beings do not merely contemplate the world. They labor, produce, exchange, struggle, build institutions, and inherit relations they did not choose. Marx asks how these relations shape what people can think, want, and become. Philosophy becomes critique of social reality, not only interpretation of concepts.",
      "His work is not one simple doctrine. It includes early writings on alienation and human activity, political journalism, historical analysis, revolutionary polemic, economic theory, and unfinished manuscripts. Marx is a critic of capitalism, a theorist of class struggle, a reader of Hegel, a critic of political economy, and a revolutionary intellectual. Responsible reading distinguishes these registers while seeing their shared concern: freedom requires transforming the social conditions that make people unfree."
    ],['political-philosophy','continental-philosophy'],['marx','hegel'],['Communist Manifesto','Capital']),
    section('industrial-context','Industrial capitalism and nineteenth-century upheaval',[
      "Marx wrote during the expansion of industrial capitalism, urban poverty, factory discipline, colonial markets, political revolution, and the growth of working-class movements. The old language of rights and citizenship had not abolished exploitation. Formal legal freedom could coexist with economic dependence. Workers might be free to sell labor in contract, yet compelled by lack of property to accept conditions set by owners. Marx's critique begins from this gap between juridical equality and material power.",
      "The nineteenth century also produced new sciences of society, statistics, political economy, and historical explanation. Adam Smith, David Ricardo, French socialism, German philosophy, and revolutionary politics all shaped Marx's questions. He did not invent concern for poverty or class, but he gave those concerns a systematic account tied to production, property, value, and historical development. His work belongs to a century asking whether modern freedom was genuine or only partial."
    ],['political-philosophy','continental-philosophy'],['marx','mill'],['Capital','Communist Manifesto']),
    section('hegel-feuerbach','From Hegel and Feuerbach to praxis',[
      "Marx begins in the atmosphere of post-Hegelian debate. Hegel had shown that social life, history, and recognition are central to freedom. Young Hegelians turned Hegelian critique against religion and political authority. Feuerbach argued that theology projects human powers onto God. Marx learned from this critique but thought it remained too contemplative. It exposed religious alienation without explaining the material social relations that make alienation persist.",
      "Praxis becomes the key. Human beings are practical, productive, social agents who transform nature and themselves. Marx's famous insistence that philosophers have interpreted the world while the point is to change it should not be read as contempt for theory. It means theory must grasp its own location inside practical life. Critique is not complete when it identifies an illusion. It must ask what social conditions produce the illusion and how those conditions can be changed."
    ],['german-idealism','political-philosophy'],['hegel','marx'],['Theses on Feuerbach','German Ideology']),
    section('alienation','Alienation and distorted human activity',[
      "In the 1844 manuscripts, Marx analyzes alienated labor under capitalism. The worker is alienated from the product, which confronts them as someone else's property; from the labor process, which becomes external and coerced; from species-being, or the shared human capacity for free conscious activity; and from other people, whose relations are mediated by competition and property. These early texts are unfinished, but they remain powerful because they connect suffering to social organization.",
      "Alienation is not merely a bad attitude toward work. It is a structural condition in which human powers appear as alien powers. The worker's activity enriches capital; social cooperation appears as market necessity; products dominate producers. Later Marx uses different vocabulary, especially commodity fetishism, exploitation, and value, but the concern persists. A society can be full of productive energy while the people producing it experience that energy as domination."
    ],['political-philosophy','ethics'],['marx','hegel'],['Economic and Philosophic Manuscripts of 1844']),
    section('historical-materialism','Historical materialism without mechanical determinism',[
      "Historical materialism begins from the way people produce and reproduce life. Every society must organize labor, tools, resources, family forms, property, and authority. These arrangements shape law, politics, morality, religion, and philosophy, though not by simple one-way causation. Marx often distinguishes productive forces, relations of production, and superstructure, but the model should not be flattened into the claim that technology automatically determines every idea.",
      "The best reading treats Marx as asking how social forms make some actions and thoughts more likely, more stable, or more contradictory. Feudal, capitalist, and other modes of production organize dependence differently. When productive forces and relations of production come into tension, crisis and struggle become possible. Human beings make history, but not under self-chosen conditions. This balanced sentence is crucial: Marx is neither a pure determinist nor a theorist of free will floating above society."
    ],['political-philosophy','continental-philosophy'],['marx'],['German Ideology','Preface to A Contribution to the Critique of Political Economy']),
    section('ideology','Ideology, critique, and false universality',[
      "Ideology in Marx is not simply a set of false opinions held by foolish people. It is a social process through which particular interests appear as universal, historical arrangements appear natural, and domination becomes difficult to see. The ideas of a ruling class can become ruling ideas because that class controls material and institutional means of production and circulation. But ideology works best when it is lived as common sense, not imposed as a visible lie.",
      "This account changes how philosophy reads moral and political language. Rights, freedom, equality, and property can express real achievements while also concealing material limits. Marx does not say that every ideal is worthless. He asks what social relations give an ideal its content. A worker and capitalist may both be formally free parties to a contract, but the material background makes that freedom unequal. Ideology critique reveals the hidden conditions behind familiar words."
    ],['political-philosophy','continental-philosophy'],['marx'],['German Ideology','Capital']),
    section('commodity-value','Commodity, value, and fetishism',[
      "Capital begins not with factories or revolution but with the commodity. A commodity has use-value, because it satisfies some need, and exchange-value, because it can be exchanged in definite proportions. Marx asks what social form makes such exchange intelligible. His labor theory of value is not a simple moral claim that workers deserve everything they make. It is an analysis of how socially necessary labor time becomes expressed through value in a capitalist economy.",
      "Commodity fetishism names the strange way social relations among people appear as relations among things. Prices, markets, money, and capital seem to possess independent power, while the human labor and social arrangements behind them disappear. This is not mere illusion in the head. The market really does confront individuals as an objective force. Marx's point is that this objectivity is socially produced. Capitalism makes human cooperation appear as an impersonal system standing over its participants."
    ],['political-philosophy','continental-philosophy'],['marx'],['Capital']),
    section('exploitation-class','Exploitation, surplus value, and class struggle',[
      "Marx's mature theory of exploitation centers on labor-power. Under capitalism, workers sell their capacity to work for wages. The value of that labor-power is tied to the cost of reproducing the worker, but labor can produce more value during the working day than the value paid in wages. The surplus is appropriated by capital. Exploitation therefore does not depend on cheating in every transaction. It can occur through formally legal exchange.",
      "Class struggle arises because capital and labor occupy opposed positions in production. Capital seeks surplus value through longer hours, greater intensity, technology, organization, and control. Workers resist, organize, and demand better conditions. Marx does not reduce every conflict to class in a crude way, but class names a structural antagonism at the heart of capitalist production. The Communist Manifesto gives this conflict a dramatic historical form; Capital analyzes its mechanisms with greater patience."
    ],['political-philosophy'],['marx'],['Capital','Communist Manifesto']),
    section('state-politics','State, rights, democracy, and revolution',[
      "Marx's political thought is often harder to summarize than his economic critique. He criticizes the modern state for separating political citizenship from everyday social inequality. In political life, people appear as equal citizens; in civil society, they remain divided by property, labor, and class power. Rights can protect individuals, but they can also express a society of isolated owners. Marx therefore asks whether political emancipation is enough without social emancipation.",
      "Revolution, for Marx, is not simply a change of rulers. It is transformation of class relations and productive life. Yet his writings leave difficult questions about institutions, law, pluralism, transition, and coercion. Later regimes that claimed Marx's name produced both emancipatory movements and severe domination. It is irresponsible to blame every later action directly on Marx, but equally irresponsible to ignore ambiguities in his account of revolutionary power. His political legacy demands historical and moral scrutiny."
    ],['political-philosophy'],['marx','mill'],['On the Jewish Question','Communist Manifesto','Critique of the Gotha Program']),
    section('capitalism-dynamics','Crisis, accumulation, and global capitalism',[
      "Marx understands capitalism as dynamic, innovative, and destructive. It revolutionizes production, expands markets, dissolves traditional relations, concentrates capital, and reorganizes the world through exchange. The Manifesto captures this restless movement with unusual literary force. Capital gives a more technical account of accumulation, competition, machinery, the working day, primitive accumulation, and crisis tendencies. Capitalism is powerful not because it is static, but because it constantly transforms its own conditions.",
      "Crisis is not accidental to the system. Competition pushes capital toward expansion, productivity gains, and pressure on labor, while markets do not transparently coordinate human need. Overproduction, falling profitability debates, credit, imperial expansion, and uneven development become recurring topics in Marxist traditions. Marx did not foresee every form of modern capitalism, including welfare states, financialization, digital platforms, or ecological crisis. But his analysis remains potent because it treats capitalism as historical, not natural."
    ],['political-philosophy','continental-philosophy'],['marx'],['Capital','Communist Manifesto']),
    section('interpretive-tensions','Humanism, science, determinism, and morality',[
      "Marx is interpreted in sharply different ways. Humanist readers emphasize alienation, praxis, and the recovery of human powers. Scientific or structural readers emphasize modes of production, value forms, and impersonal laws of motion. Some read Marx as a moral critic of exploitation; others argue that he avoids moralism by showing capitalism's contradictions historically. These tensions are not simply mistakes by commentators. Marx's own writings shift in genre, vocabulary, and emphasis.",
      "There are also hard questions about prediction and agency. Did Marx expect capitalism to collapse inevitably, or did he analyze tendencies that require political struggle? Does communism name a determinate institutional plan or a regulative horizon beyond class domination? How should gender, race, colonialism, ecology, and state violence be integrated into Marx's framework? Later Marxist, feminist, anti-colonial, ecological, and critical theorists develop these questions by extending and criticizing him."
    ],['political-philosophy','continental-philosophy','ethics'],['marx','hegel'],['Economic and Philosophic Manuscripts of 1844','Capital']),
    section('legacy-reading','Influence, misunderstandings, and how to read Marx',[
      "Marx influenced socialist movements, labor organizing, social theory, economics, history, literary criticism, anthropology, political theology, liberation movements, and critical theory. He also became the symbolic center of immense political conflicts. This makes reading him difficult. Some readers approach with devotion; others with inherited hostility. A responsible approach neither treats Marx as a prophet nor dismisses him because later Marxist politics were morally compromised. Read the arguments and the histories together.",
      "Begin with the Theses on Feuerbach and selected early writings on alienation, then read the Communist Manifesto as a polemical historical text rather than a complete theory. Move to Capital, especially chapters on the commodity, money, the working day, machinery, and primitive accumulation. Read slowly enough to distinguish value analysis from slogans about class. Keep Hegel in the background, but also read political economy and labor history. Marx is clearest when philosophy, economics, and social struggle are kept in one frame.",
      "The most common mistake is to turn Marx into either a moral preacher or a cold economic determinist. He is more unsettling than both. He asks how moral life is shaped by material dependence, and how impersonal systems are reproduced by ordinary actions. That means critique has to examine exploitation, but also the everyday forms of consent, necessity, fear, hope, and habit through which a social order continues. Concrete cases keep the critique from becoming only a vocabulary of suspicion."
    ],['political-philosophy','continental-philosophy'],['marx','hegel','mill'],['Theses on Feuerbach','Communist Manifesto','Capital'])
  ],
  mill:[
    section('overview','Utility, liberty, and the education of individuality',[
      "John Stuart Mill is the most influential nineteenth-century defender of liberal liberty and one of the major revisers of utilitarianism. He inherits Bentham's project of evaluating institutions and actions by their consequences for happiness, but he gives that project a richer account of character, individuality, freedom of thought, education, and equality. Mill's philosophy asks how social arrangements can promote well-being without crushing the development of persons.",
      "He is often read as two philosophers at once: a utilitarian who wants the greatest happiness and a liberal who protects individual liberty against majority pressure. Mill himself thought these belonged together. A society that silences dissent, enforces conformity, excludes women, or stunts individuality damages human happiness at its roots. Utility is not just a sum of immediate pleasures. It concerns the flourishing of beings capable of thought, experiment, sympathy, and self-development."
    ],['utilitarianism','political-philosophy','ethics'],['mill'],['Utilitarianism','On Liberty']),
    section('formation','Benthamite education and a crisis of development',[
      "Mill was born in 1806 and educated intensely by his father James Mill under the influence of Jeremy Bentham. He learned Greek, logic, economics, history, and utilitarian reform at an age when most children were beginning formal schooling. The education made him brilliant and disciplined, but also emotionally constricted. In his twenties he experienced a mental crisis, wondering whether achieving all his reforming goals would actually make him happy.",
      "This crisis matters philosophically. Mill came to think that Benthamite rational reform needed poetry, feeling, individuality, and cultivated character. Wordsworth and Romantic literature helped him see that happiness cannot be produced only by institutional calculation or external improvement. He did not abandon utilitarianism, but he transformed its psychology. Human beings need developed capacities, not merely efficient satisfaction. This gives Mill's later liberalism its depth: freedom matters partly because persons must grow from within."
    ],['utilitarianism','ethics'],['mill'],['Autobiography']),
    section('utilitarianism','Utilitarianism and the quality of pleasures',[
      "In Utilitarianism, Mill defends the principle that actions are right insofar as they tend to promote happiness and wrong insofar as they tend to produce the reverse. Happiness means pleasure and absence of pain, but Mill departs from a crude version of hedonism by distinguishing higher and lower pleasures. Pleasures of intellect, imagination, moral feeling, and human affection may be more valuable than bodily pleasures, even when accompanied by dissatisfaction.",
      "The famous appeal to competent judges is meant to show that people acquainted with both sorts of pleasure generally prefer the higher mode of life. Critics ask whether this smuggles in non-hedonistic values such as dignity, autonomy, or excellence. Mill might answer that these are components of human happiness once our capacities are developed. The issue remains central: can utilitarianism make room for qualitative forms of life without abandoning its consequentialist foundation?"
    ],['utilitarianism','ethics'],['mill'],['Utilitarianism']),
    section('proof-utility','The proof of utility and moral motivation',[
      "Mill's proof of the principle of utility is one of the most debated passages in his work. He argues that the only evidence something is desirable is that people actually desire it, and that each person's happiness is a good to that person, so general happiness is a good to the aggregate of persons. Critics have long challenged the inference from desired to desirable and from individual goods to general good. Mill's argument is better read as an appeal to reflective practical evidence than as a strict deduction.",
      "He also explains moral motivation through internal sanctions, sympathy, education, and the feeling of unity with others. Utilitarian morality is not meant to require cold calculation before every act. Rules, habits, and character matter because they embody accumulated experience about consequences. This helps answer the charge that utilitarianism is too demanding or too mechanical. Yet tensions remain about justice, rights, promises, and whether maximizing happiness can protect individuals strongly enough."
    ],['utilitarianism','ethics'],['mill'],['Utilitarianism']),
    section('liberty','On Liberty and the harm principle',[
      "On Liberty argues that power may be rightfully exercised over an individual against their will only to prevent harm to others. A person's own good, physical or moral, is not sufficient warrant for coercion. This harm principle targets both state compulsion and social tyranny, the pressure of custom and public opinion. Mill worries that democratic societies can become oppressive not only through rulers, but through majorities that enforce conformity.",
      "The principle is not simple in application. What counts as harm rather than offense, distaste, self-regarding damage, or indirect social cost? Mill's own examples leave room for debate. Still, the central insight is powerful: adults need protected space for judgment, experiment, and responsibility. A society that prevents every risky or unpopular choice may produce obedience, but not mature persons. Liberty is valuable because human beings learn by living, not only by being managed."
    ],['political-philosophy','ethics'],['mill'],['On Liberty']),
    section('speech','Freedom of thought, discussion, and fallibility',[
      "Mill's defense of free discussion rests on human fallibility. A silenced opinion may be true. If false, it may contain part of the truth. Even if wholly false, contesting it can keep true beliefs alive as understood convictions rather than dead dogmas. This is not a lazy marketplace slogan. Mill thinks truth requires active testing because human beings are prone to complacency, social pressure, and inherited prejudice.",
      "His argument remains important and contested. Modern readers ask how it applies to propaganda, harassment, unequal access to platforms, misinformation, and speech that helps sustain domination. Mill did not solve every contemporary problem. But he offers a demanding standard for intellectual life: a belief held without understanding opposing arguments is often held poorly. Freedom of discussion is not only a right of speakers. It is an educational condition for everyone who must think."
    ],['political-philosophy','epistemology'],['mill'],['On Liberty']),
    section('individuality','Individuality as an element of well-being',[
      "Mill's liberalism is not only about privacy or noninterference. He argues that individuality is one of the elements of well-being. Human nature is not a machine built after a model, but something that grows according to inward forces when given room. Experiments in living allow people and societies to discover better ways of being. Conformity, even to respectable norms, can stunt capacities and make life shallow.",
      "This theme connects Mill to Romanticism as well as utilitarian reform. Individuality is not selfish eccentricity. It is the development of judgment, taste, feeling, and responsibility. A person who never chooses because custom chooses for them lacks an important part of happiness. Mill's emphasis can understate how poverty, disability, gender, race, and labor conditions limit real options. Still, he gives liberalism a developmental ideal rather than a merely protective one."
    ],['political-philosophy','ethics'],['mill'],['On Liberty']),
    section('women-equality','The subjection of women and liberal equality',[
      "The Subjection of Women argues that legal and social subordination of women is one of the chief obstacles to human improvement. Mill rejects the claim that existing gender roles reveal natural capacities, because those roles were formed under coercion and dependency. One cannot infer what women are fit for from a society that has denied them education, property rights, political voice, and open competition.",
      "The work was shaped by Mill's long intellectual partnership with Harriet Taylor Mill, whose influence on his thought remains important and sometimes difficult to specify precisely. Mill's argument joins justice and utility: equality is right, and society wastes immense human capacity by subordination. Modern feminism has criticized limits in Mill's framework, including its liberal individualism and class assumptions. Even so, the book remains a landmark in philosophical arguments for gender equality."
    ],['political-philosophy','ethics','utilitarianism'],['mill'],['The Subjection of Women']),
    section('democracy-government','Representative government and democratic danger',[
      "Mill defended representative government because people develop capacities by participating in public life and because accountable institutions can promote common interests better than despotism. But he also feared ignorance, class legislation, bureaucracy, and the tyranny of majority opinion. His political writings therefore combine democratic aspiration with institutional safeguards, plural voting proposals, proportional representation, local participation, and concern for competent administration.",
      "This mixture is uncomfortable for modern readers. Mill's confidence in education and competence sometimes leads him toward elitist devices. His writings on empire and civilization include serious limitations and prejudices that should not be excused by admiration for On Liberty. The best reading holds the tension in view. Mill helps us ask how democracy can educate citizens and protect liberty, while his own exclusions reveal how easily liberal standards can be applied unevenly."
    ],['political-philosophy'],['mill'],['Considerations on Representative Government','On Liberty']),
    section('logic-empiricism','Empiricism, logic, and the sciences of society',[
      "Mill was also a major logician and empiricist. A System of Logic develops methods of experimental inquiry, induction, causation, and evidence. He rejects innate ideas and tries to explain knowledge through experience, association, and scientific method. His methods of agreement and difference became famous tools for causal reasoning, even though later philosophy of science revised them heavily.",
      "He wanted moral and social sciences to be empirical without becoming simplistic. Human behavior is shaped by many causes, so prediction is difficult, but not impossible in principle. This ambition connects his epistemology to reform. If institutions produce suffering, ignorance, or dependency, social inquiry should identify causes and alternatives. Mill's empiricism is therefore practical. Knowledge matters because better understanding can guide law, education, economy, and public debate."
    ],['epistemology','philosophy-of-science'],['mill'],['A System of Logic']),
    section('political-economy','Political economy, labor, and cautious socialism',[
      "Mill's Principles of Political Economy accepts many classical economic ideas but treats distribution as more changeable than production. The laws governing production may depend on technical and material constraints, but distribution is shaped by human institutions, law, custom, and choice. This distinction allowed Mill to support private property in some contexts while considering cooperative production, labor organization, inheritance limits, and social reforms.",
      "Late in life, Mill became more sympathetic to forms of socialism, especially worker cooperatives, though he remained wary of centralized control and threats to liberty. This is important because it complicates the image of Mill as a simple defender of laissez-faire capitalism. He sought arrangements that would combine individual development, economic security, and social cooperation. Whether that balance is stable remains debated, but the question is central to liberal political economy."
    ],['political-philosophy','utilitarianism'],['mill','marx'],['Principles of Political Economy']),
    section('legacy-reading','Influence, tensions, and how to read Mill',[
      "Mill's influence reaches liberalism, utilitarian ethics, free speech theory, feminism, democratic theory, political economy, and philosophy of science. He remains useful because he connects institutional reform with the cultivation of persons. He remains controversial because his commitments pull against one another: utility and rights, liberty and social improvement, democracy and competence, empiricism and qualitative value, anti-paternalism and colonial assumptions.",
      "A good reading path begins with On Liberty, then Utilitarianism, then The Subjection of Women. Add chapters from the Autobiography to understand the emotional and educational background, and selections from Representative Government and Political Economy for institutional context. Read Mill as a thinker revising his inheritance rather than merely repeating Bentham. The most productive question is not whether he is purely liberal or purely utilitarian, but how he tries to make liberty answerable to human flourishing. His limits belong inside that assessment, not in a footnote.",
      "Beginners should also notice Mill's habit of arguing with himself. He often states a principle, then turns to the cases that make it difficult: harmful speech, bad choices, dependent education, unequal marriage, incompetent voters, stagnant custom, and economic insecurity. That habit is why he remains teachable. Mill gives readers principles, but he also shows that principles become serious only when they meet awkward social facts.",
      "One final caution is to read Mill historically and critically at once. His arguments for liberty and equality can still challenge paternalism, censorship, and gender hierarchy, but his limits on empire, class, and competence show how liberal confidence can coexist with exclusion. The point is not to cancel the useful arguments. It is to let Mill's own standard of open criticism apply to Mill himself, especially where his principles outrun his inherited assumptions."
    ],['utilitarianism','political-philosophy','ethics'],['mill','marx'],['On Liberty','Utilitarianism','The Subjection of Women','Autobiography'])
  ]
};
